// Generar combinaciones módulo × versión para comprobaciones posteriores.
// Toma la salida del nodo de clasificación (IA) y construye items
// { modulo, version, es_oca, origen, repo_inicial, ... }.

const versiones = ['12.0','13.0','14.0','15.0','16.0','17.0','18.0','19.0'];

const version_origen = $json.version_origen || '12.0';
const version_objetivo = $json.version_objetivo || '17.0';

const iOrigen = versiones.indexOf(version_origen);
const iObjetivo = versiones.indexOf(version_objetivo);

// Preferimos $json.modulos (salida de la IA). Si no existe, usamos modulos_pre.
const base = Array.isArray($json.modulos)
  ? $json.modulos
  : (Array.isArray($json.modulos_pre) ? $json.modulos_pre : []);

const salida = [];

for (const m of base) {
  const modulo = m.modulo || m.nombre_detectado || '';
  if (!modulo) continue;

  const es_oca = !!m.es_oca || m.origen === 'oca';
  const origen = es_oca ? 'oca' : 'desconocido';
  const repo_inicial = m.repo_inicial || '';
  const index = m.index ?? 0;

  for (let i = 0; i < versiones.length; i++) {
    const v = versiones[i];

    if (iOrigen !== -1 && iObjetivo !== -1) {
      const min = Math.min(iOrigen, iObjetivo);
      const max = Math.max(iOrigen, iObjetivo);
      if (i < min || i > max) continue;
    }

    salida.push({
      index,
      modulo,
      es_oca,
      origen,
      repo_inicial,
      version: v,
      version_origen,
      version_objetivo,
    });
  }
}

return salida;

// Transformar la salida del AI Agent en filas para CSV.
// El agente suele devolver el JSON dentro de la propiedad `output`
// como string. Ejemplo:
//   { output: "{ \"version_origen\":..., \"modulos\":[...] }" }
// Este código intenta primero usar $json directamente y, si no hay
// `modulos`, intenta parsear $json.output.

function parsearOutput(output) {
  if (!output) return null;
  if (typeof output === 'object') return output;
  if (typeof output !== 'string') return null;

  // El agente a veces antepone 'json' o espacios, o incluso ```json ... ```.
  // Buscamos el primer '{' y el último '}' y parseamos ese trozo.
  const inicio = output.indexOf('{');
  const fin = output.lastIndexOf('}');
  if (inicio === -1 || fin === -1 || fin <= inicio) return null;

  const posibleJson = output.slice(inicio, fin + 1);
  try {
    return JSON.parse(posibleJson);
  } catch (e) {
    return null;
  }
}

let data = $json || {};

// Si no vienen modulos directamente, intentamos sacarlos de `output`.
if (!Array.isArray(data.modulos) || data.modulos.length === 0) {
  const desdeOutput = parsearOutput(data.output || data.result || data.data);
  if (desdeOutput && Array.isArray(desdeOutput.modulos)) {
    data = desdeOutput;
  }
}

const version_origen = data.version_origen || '12.0';
const version_objetivo = data.version_objetivo || '17.0';

const modulos = Array.isArray(data.modulos) ? data.modulos : [];

if (modulos.length === 0) {
  return [
    {
      modulo: '',
      origen: 'desconocido',
      repo_inicial: '',
      version_odoo_origen: version_origen,
      version_odoo_objetivo: version_objetivo,
      v12: 'NO',
      v13: 'NO',
      v14: 'NO',
      v15: 'NO',
      v16: 'NO',
      v17: 'NO',
      v18: 'NO',
      v19: 'NO',
      motivo_si_no: 'Sin módulos en la respuesta del agente (revisar salida de AI Agent)',
      nombre_detectado: '',
      contexto: '',
    },
  ];
}

const filas = modulos.map(m => ({
  modulo: m.modulo || m.nombre_tecnico || '',
  origen: (m.origen || 'desconocido').toLowerCase(),
  repo_inicial: m.repo_inicial || '',
  version_odoo_origen: m.version_odoo_origen || version_origen,
  version_odoo_objetivo: m.version_odoo_objetivo || version_objetivo,
  v12: m.v12 || 'NO',
  v13: m.v13 || 'NO',
  v14: m.v14 || 'NO',
  v15: m.v15 || 'NO',
  v16: m.v16 || 'NO',
  v17: m.v17 || 'NO',
  v18: m.v18 || 'NO',
  v19: m.v19 || 'NO',
  motivo_si_no: m.motivo_si_no || '',
  nombre_detectado: m.nombre_detectado || m.modulo || '',
  contexto: m.contexto || '',
}));

return filas;

// Construir matriz de versiones 12.0–19.0 para TODOS los módulos
// recibidos en modulos_pre, sin depender de la IA.

const version_origen = $json.version_origen || '12.0';
const version_objetivo = $json.version_objetivo || '17.0';

const versiones = ['12.0', '13.0', '14.0', '15.0', '16.0', '17.0', '18.0', '19.0'];
const idxOrigen = versiones.indexOf(version_origen);
const idxObjetivo = versiones.indexOf(version_objetivo);

const modulos_pre = Array.isArray($json.modulos_pre) ? $json.modulos_pre : [];

function rangoIncluye(idx, a, b) {
  const min = Math.min(a, b);
  const max = Math.max(a, b);
  return idx >= min && idx <= max;
}

const modulos = modulos_pre.map(orig => {
  const nombre = orig.modulo || '';
  const origen = (orig.origen || 'desconocido').toLowerCase();

  const m = {
    modulo: nombre,
    origen,
    repo_inicial: '',
    version_odoo_origen: version_origen,
    version_odoo_objetivo: version_objetivo,
    nombre_detectado: nombre,
    contexto: '',
  };

  versiones.forEach((v, idx) => {
    const col = 'v' + v.split('.')[0];
    let valor = 'NO';

    if (origen === 'oca') {
      // Heurística simple: SI desde origen hasta objetivo (incluidos)
      if (idxOrigen !== -1 && idxObjetivo !== -1 && rangoIncluye(idx, idxOrigen, idxObjetivo)) {
        valor = 'SI';
      }
    } else {
      // Desconocido/custom: SI solo en la versión de origen
      if (idxOrigen !== -1 && idx === idxOrigen) {
        valor = 'SI';
      }
    }

    m[col] = valor;
  });

  const colObjetivo = 'v' + version_objetivo.split('.')[0];
  if (m[colObjetivo] === 'SI') {
    m.motivo_si_no = 'Disponible en la versión objetivo.';
  } else {
    m.motivo_si_no = 'Sin información clara, revisar manualmente.';
  }

  return m;
});

return {
  version_origen,
  version_objetivo,
  modulos,
};

// Detectar módulos de forma GENERAL a partir del texto del PDF.
// Regla: cualquier token en snake_case (letras/números con '_')
// se considera candidato a módulo.

// 1) Construimos un texto bruto a partir de los campos más típicos
let bruto = '';

if (typeof $json.text === 'string') {
  bruto += $json.text;
}
if (typeof $json.texto_pdf === 'string') {
  // Compatibilidad con versiones anteriores del flujo
  bruto += '\n' + $json.texto_pdf;
}

// Si no hay nada, devolvemos sin módulos
if (!bruto) {
  return {
    version_origen: $json.version_origen,
    version_objetivo: $json.version_objetivo,
    modulos_pre: [],
  };
}

// 2) Normalizar saltos de línea Windows
bruto = bruto.replace(/\r\n/g, '\n');

// 3) Unir palabras partidas por guion + salto de línea
//    (ej: "account-\nmove" -> "accountmove")
bruto = bruto.replace(/-\s*\n\s*/g, '');

// 4) Unir SOLO saltos de línea dentro de nombres en snake_case
//    (ej: "hr_timesheet_sheet_attend\nance" -> "hr_timesheet_sheet_attendance")
//    Requiere que la parte izquierda tenga al menos un '_' para no unir
//    palabras normales como "Contabilidad\ngst_solar_lot".
bruto = bruto.replace(/([a-z0-9]*_[a-z0-9]*)\s*\n\s*([a-z0-9]+)/gi, '$1$2');

// 5) Convertir el resto de saltos de línea y tabs en espacios
let texto = bruto.replace(/[\n\t]+/g, ' ');

// 6) Colapsar espacios múltiples
texto = texto.replace(/\s+/g, ' ').trim();

// 7) Regex genérico para snake_case: al menos un '_', SOLO minúsculas y dígitos.
//    Esto evita arrastrar colas como "transferBankingaddonsAdd".
const regex = /\b[a-z0-9]+(?:_[a-z0-9]+)+\b/g;
const encontrados = new Set();
let match;

while ((match = regex.exec(texto)) !== null) {
  encontrados.add(match[0]); // mantiene el caso tal como aparece
}

// 8) Convertimos a lista ordenada, con índice estable, y la envolvemos en objetos
const modulos_pre = Array.from(encontrados)
  .sort((a, b) => a.localeCompare(b))
  .map((nombre, index) => ({ index, modulo: nombre, origen: 'desconocido' }));

const parsed = $('Parsear Versiones').first().json;

return {
  version_origen: parsed.version_origen || '12.0',
  version_objetivo: parsed.version_objetivo || '17.0',
  modulos_pre,
};

// Parsear versiones de Odoo desde texto o caption de Telegram.
// Formatos soportados:
// - "estoy en 13.0 quiero 17.0"
// - "origen 13.0 destino 17.0"
// - "12.0 -> 17.0" / "12.0 17.0"

const msg = $json.message || {};
const mensaje = msg.text || msg.caption || '';

if (!msg.document) {
  throw new Error('Adjunta un CSV (lista de módulos) o un PDF. En el caption indica versiones, ej: estoy en 13.0 quiero 17.0');
}

const doc = msg.document;
const fileName = (doc.file_name || '').toLowerCase();
const mimeType = (doc.mime_type || '').toLowerCase();
const es_csv = fileName.endsWith('.csv') || mimeType.includes('csv') || mimeType === 'text/plain';

const versiones = Array.from(mensaje.matchAll(/\b(1[0-9]|[0-9])\.0\b/g)).map(m => m[1] + '.0');

let version_origen = versiones[0] || '12.0';
let version_objetivo = versiones[1] || '17.0';

const lower = mensaje.toLowerCase();

const matchEstoyEn = lower.match(/estoy en\s*(1[0-9]|[0-9])\.0/);
if (matchEstoyEn) version_origen = matchEstoyEn[1] + '.0';

const matchQuiero = lower.match(/quiero\s*(1[0-9]|[0-9])\.0/);
if (matchQuiero) version_objetivo = matchQuiero[1] + '.0';

const matchOrigen = lower.match(/origen\s*(1[0-9]|[0-9])\.0/);
if (matchOrigen) version_origen = matchOrigen[1] + '.0';

const matchDestino = lower.match(/(destino|objetivo)\s*(1[0-9]|[0-9])\.0/);
if (matchDestino) version_objetivo = matchDestino[2] + '.0';

return {
  ...$json,
  version_origen,
  version_objetivo,
  es_csv,
  mensaje_parseado: mensaje,
};

// BUCLE 1: Listar todos los repositorios OCA desde GitHub
const input = $input.first().json;
const spreadsheetId = (input.spreadsheet_id || '').trim();
const sheetName = (input.sheet_name || 'oca_repo_mapping').trim();
const githubToken = (input.github_token || '').trim();

if (!githubToken) throw new Error('github_token vacío.');
if (!spreadsheetId) throw new Error('spreadsheet_id obligatorio (ID de la hoja de Google Sheets).');

const EXCLUDE_REPOS = new Set(['odoo-community.org','OCA.github.io','maintainer-tools','ocabot','oca-addons-repo','oca-port','odoo-module-migrator','openupgrade','runbot-addons']);
const ghHeaders = { 'Authorization': `Bearer ${githubToken}`, 'Accept': 'application/vnd.github.v3+json' };

async function gh(url) {
  const r = await this.helpers.httpRequest({ url, headers: ghHeaders });
  await new Promise(r => setTimeout(r, 200));
  return r;
}

let page = 1;
let repos = [];
while (true) {
  const batch = await gh.call(this, `https://api.github.com/orgs/OCA/repos?per_page=100&page=${page}`);
  if (!Array.isArray(batch) || batch.length === 0) break;
  repos = repos.concat(batch);
  if (batch.length < 100) break;
  page++;
}

const addonRepos = repos.filter(r => !EXCLUDE_REPOS.has(r.name) && !r.name.startsWith('.') && r.name !== 'website');

return addonRepos.map(r => ({
  json: {
    repo: r.name,
    spreadsheet_id: spreadsheetId,
    sheet_name: sheetName,
    github_token: githubToken
  }
}));

// BUCLE 2: Para cada repo, listar módulos de TODAS las versiones 12.0-19.0 (sin duplicados)
// Un módulo puede existir solo en 13.0 y no en 12.0, por eso scout todas las ramas
const items = $input.all();
const item = items[0]?.json || {};
const repo = item.repo;
const githubToken = (item.github_token || '').trim();
const spreadsheetId = (item.spreadsheet_id || '').trim();
const sheetName = (item.sheet_name || 'oca_repo_mapping').trim();

const MODULE_REGEX = /^[a-z0-9]+(_[a-z0-9]+)+$/;
const VERSIONES = ['12.0','13.0','14.0','15.0','16.0','17.0','18.0','19.0'];
const ghHeaders = { 'Authorization': `Bearer ${githubToken}`, 'Accept': 'application/vnd.github.v3+json' };

// Map: modulo -> Set de versiones donde se encontró
const modulosEncontrados = new Map();

for (const version of VERSIONES) {
  try {
    const contents = await this.helpers.httpRequest({
      url: `https://api.github.com/repos/OCA/${repo}/contents?ref=${version}`,
      headers: ghHeaders
    });
    await new Promise(r => setTimeout(r, 180));
    if (Array.isArray(contents)) {
      for (const c of contents) {
        if (c.type === 'dir' && MODULE_REGEX.test(c.name) && !c.name.startsWith('.')) {
          if (!modulosEncontrados.has(c.name)) {
            modulosEncontrados.set(c.name, new Set());
          }
          modulosEncontrados.get(c.name).add(version);
        }
      }
    }
  } catch (e) {}
  await new Promise(r => setTimeout(r, 150));
}

const modulos = Array.from(modulosEncontrados.entries()).map(([modulo, versionesSet]) => ({
  modulo,
  repo,
  versiones_disponibles: Array.from(versionesSet).sort(),
  versiones_completas: false,
  updated_at: new Date().toISOString()
}));

if (modulos.length === 0) {
  return [{ json: { repo: repo, modulo: '', _passthrough: true } }];
}

return modulos.map(m => ({
  json: {
    modulo: m.modulo,
    repo: m.repo,
    versiones_disponibles: JSON.stringify(m.versiones_disponibles),
    versiones_completas: m.versiones_completas,
    updated_at: m.updated_at,
    spreadsheet_id: spreadsheetId,
    sheet_name: sheetName
  }
}));

// Reducir a 1 item para que Get Rows solo haga 1 lectura (evitar 429 quota)
const items = $input.all();
const withCreds = items.find(i => i.json?.spreadsheet_id) || items[0];
const creds = $('Credenciales (editar)').first().json;
const data = withCreds?.json || creds;
return data?.spreadsheet_id ? [{ json: { spreadsheet_id: data.spreadsheet_id, sheet_name: data.sheet_name || 'oca_repo_mapping' } }] : [];

// Filtrar módulos con versiones_completas=false y limitar a 50
const items = $input.all();
const rows = items.map(i => i.json);
const pendientes = rows.filter(r => {
  const vc = r.versiones_completas;
  if (typeof vc === 'boolean') return !vc;
  if (typeof vc === 'string') return vc.toLowerCase() !== 'true' && vc !== '1';
  return true;
})

const creds = $('Credenciales (editar)').first().json;
return pendientes.map(p => ({
  json: {
    modulo: p.modulo,
    repo: p.repo,
    spreadsheet_id: creds.spreadsheet_id,
    sheet_name: creds.sheet_name,
    github_token: creds.github_token
  }
}));

// Añadir github_token a cada módulo para Bucle 4
const creds = $('Credenciales (editar)').first().json;
const token = (creds.github_token || '').trim();
const items = $input.all();
return items.map(i => ({ json: { ...i.json, github_token: token } }));

// BUCLE 4: Para cada módulo, comprobar versiones 12.0-19.0 en GitHub
const items = $input.all();
const item = items[0]?.json || {};
const modulo = item.modulo;
const repo = item.repo;
const githubToken = (item.github_token || '').trim();
const spreadsheetId = (item.spreadsheet_id || '').trim();
const sheetName = (item.sheet_name || 'oca_repo_mapping').trim();

const VERSIONES = ['12.0','13.0','14.0','15.0','16.0','17.0','18.0','19.0'];
const ghHeaders = { 'Authorization': `Bearer ${githubToken}`, 'Accept': 'application/vnd.github.v3+json' };

let versiones = [];
for (const v of VERSIONES) {
  try {
    await this.helpers.httpRequest({
      url: `https://api.github.com/repos/OCA/${repo}/contents/${modulo}?ref=${v}`,
      headers: ghHeaders
    });
    versiones.push(v);
  } catch (e) {}
  await new Promise(r => setTimeout(r, 150));
}

return [{
  json: {
    modulo,
    repo,
    versiones_disponibles: JSON.stringify(versiones.sort()),
    versiones_completas: true,
    updated_at: new Date().toISOString(),
    spreadsheet_id: spreadsheetId,
    sheet_name: sheetName
  }
}];

// Leer lista de módulos desde CSV enviado por Telegram.
// Columna esperada: 'modulo' (también acepta module, nombre, name o 1ª columna).

const parsed = $('Parsear Versiones').first().json;
const version_origen = parsed.version_origen || '12.0';
const version_objetivo = parsed.version_objetivo || '17.0';

const MODULE_REGEX = /^[a-z0-9]+(_[a-z0-9]+)+$/;
const modulosSet = new Set();

for (const item of $input.all()) {
  const row = item.json || {};
  const candidatos = [
    row.modulo,
    row.module,
    row.nombre,
    row.name,
    row.Modulo,
    row.Module,
  ];

  const primeraCol = Object.values(row).find(v => typeof v === 'string' && v.trim());
  if (primeraCol) candidatos.push(primeraCol);

  for (const raw of candidatos) {
    if (!raw) continue;
    const nombre = String(raw).trim().toLowerCase().replace(/\s+/g, '');
    if (MODULE_REGEX.test(nombre)) modulosSet.add(nombre);
  }
}

const modulos_pre = Array.from(modulosSet)
  .sort((a, b) => a.localeCompare(b))
  .map((nombre, index) => ({ index, modulo: nombre, origen: 'desconocido' }));

if (modulos_pre.length === 0) {
  throw new Error('El CSV no tiene módulos válidos. Usa columna "modulo" con nombres técnicos en snake_case (ej: sale_order).');
}

return {
  version_origen,
  version_objetivo,
  modulos_pre,
};
